// ============================================================================
// Brandy - Code Node: Prepare Data
// ============================================================================
// Merges webhook body + Supabase brand data + conversation state
// Outputs flat JSON for AI Agent mustache variables
// ============================================================================

const webhookBody = $('Webhook').first().json.body;
// getAll returns array of results - take first item or empty object
const supabaseResults = $('Supabase - Get Brand Data').first().json;
const brandData = Array.isArray(supabaseResults) ? (supabaseResults[0] || {}) : (supabaseResults || {});

// Parse incoming state (frontend sends as 'state', fallback to 'conversation_state')
let incomingState = {};
try {
  const rawState = webhookBody.state || webhookBody.conversation_state;
  if (rawState) {
    incomingState = typeof rawState === 'string' ? JSON.parse(rawState) : rawState;
  }
} catch(e) {
  incomingState = {};
}

// Check if brand data exists in Supabase
const hasBrandData = !!(brandData.atmosphere || brandData.rebellious_edge || brandData.enemy_statement);

// Determine default phase
let defaultPhase = 'assessment';
if (incomingState.phase) {
  defaultPhase = incomingState.phase;
} else if (hasBrandData) {
  defaultPhase = 'advisor';
}

// Build conversation state with defaults
const state = {
  phase: defaultPhase,
  brand_exists: hasBrandData,
  wizard_step: incomingState.wizard_step || 0,
  wizard_data: incomingState.wizard_data || {},
  import_status: incomingState.import_status || null
};

// Format brand data for AI context
let brandSummary = 'No brand data exists yet.';
if (hasBrandData) {
  brandSummary = `EXISTING BRAND FOUNDATION:\n- Atmosphere: ${brandData.atmosphere || 'not set'}\n- Rebellious Edge: ${brandData.rebellious_edge || 'not set'}\n- Enemy: ${brandData.enemy_statement || 'not set'}\n- Visual Direction: ${brandData.visual_direction || 'not set'}\n- Hook Style: ${brandData.hook_style || 'not set'}\n- Voice: ${brandData.voice_messaging || 'not set'}`;
  if (brandData.full_brand_bible) {
    brandSummary += '\n- Full Brand Bible: EXISTS';
  }
}

return [{
  json: {
    // Webhook identifiers
    user_id: webhookBody.user_id,
    user_mssg: webhookBody.user_mssg,
    session_id: webhookBody.session_id,
    agent_name: 'brandy',
    timestamp_of_call_made: webhookBody.timestamp_of_call_made,
    request_id: webhookBody.request_id,

    // Brand context
    brand_exists: hasBrandData,
    brand_summary: brandSummary,
    brand_data_json: JSON.stringify(brandData),

    // Conversation state for AI
    conversation_state: JSON.stringify(state, null, 2)
  }
}];

